#include <iostream>
#include <string>
#include <sstream>

// Assume isPrime(int n) is defined in the user's code.
// The user's main function is ignored; this driver calls isPrime directly.

extern bool isPrime(int n);

int main() {
    std::string line;
    while (std::getline(std::cin, line)) {
        std::stringstream ss(line);
        int num;
        if (!(ss >> num)) {
            std::cout << "Invalid input." << std::endl;
            continue;
        }

        if (num <= 0) {
            std::cout << "Please enter a positive integer." << std::endl;
        } else {
            if (isPrime(num)) {
                std::cout << num << " is a prime number." << std::endl;
            } else {
                std::cout << num << " is not a prime number." << std::endl;
            }
        }
    }
    return 0;
}
